import React from "react";
import styles from "./RegisterError.module.css";

interface RegisterErrorProps {
  onSwitchToLogin: () => void;
  onClose: () => void;
  errorMessage: string;
}

const RegisterError: React.FC<RegisterErrorProps> = ({
  onSwitchToLogin,
  onClose,
  errorMessage,
}) => {
  return (
    <div className={styles.registerErrorContainer}>
      <img
        src={`${process.env.PUBLIC_URL}/images/logo.svg`}
        alt="SkyFitnessPro"
        className={styles.logo}
      />

      <div className={styles.formContainer}>
        <input
          type="email"
          placeholder="Эл.почта"
          className={styles.inputField}
        />

        <input
          type="password"
          placeholder="Пароль"
          className={styles.inputField}
        />

        <input
          type="password"
          placeholder="Повторить пароль"
          className={styles.inputField}
        />

        <div className={styles.errorMessage}>{errorMessage}</div>

        <button className={styles.registerButton} onClick={onClose}>
          Зарегистрироваться
        </button>

        <button className={styles.loginButton} onClick={onSwitchToLogin}>
          Войти
        </button>
      </div>
    </div>
  );
};

export default RegisterError;
